import requests
from flask import Flask, request, jsonify
from flask_httpauth import HTTPBasicAuth
from werkzeug.security import generate_password_hash, check_password_hash
from pyotp import TOTP

app = Flask(__name__)
auth = HTTPBasicAuth()

# In-memory storage for users (in a real application, use a database)
users = {
    'user1': generate_password_hash('password1'),
    'user2': generate_password_hash('password2')
}

# In-memory storage for tokens (in a real application, use a database)
tokens = {}

# Generate a secret key for the TOTP algorithm
secret_key = TOTP.random_base32()

@auth.verify_password
def verify_password(username, password):
    if username in users:
        return check_password_hash(users.get(username), password)
    return False

@app.route('/login', methods=['POST'])
def login():
    username = request.json.get('username')
    password = request.json.get('password')
    if verify_password(username, password):
        # Generate a new token and store it in memory
        token = TOTP.generate(secret_key)
        tokens[token] = username
        return jsonify({'token': token})
    return jsonify({'error': 'Invalid username or password'}), 401

@app.route('/logout', methods=['POST'])
def logout():
    token = request.json.get('token')
    if token in tokens:
        del tokens[token]
        return jsonify({'message': 'Logged out successfully'})
    return jsonify({'error': 'Invalid token'}), 401

@app.route('/protected', methods=['GET'])
@auth.login_required
def protected():
    return jsonify({'message': 'Hello, ' + auth.current_user()})

if __name__ == '__main__':
    app.run(debug=True)

