            res.status(401).json({ message: 'Invalid username or password' });
            return;
        }
        const isValidPassword = await bcrypt.compare(password, user.password);
        if (!isValidPassword) {
            res.status(401).json({ message: 'Invalid username or password' });
            return;
        }
        const token = jwt.sign({ userId: user._id }, tokenSecret, { expiresIn: '1h' });
